def longestCommonPrefix(list_of_strings):
    if not list_of_strings:
        return ""
    # The first string in the list will serve as our reference for building the prefix
    reference_string = list_of_strings[0]
    for prefix_length in range(1, len(reference_string) + 1):
        potential_prefix = reference_string[:prefix_length]
        # For each potential prefix, we must verify it's at the start of ALL other strings
        is_common_to_all = True
        for i in range(1, len(list_of_strings)):
            current_string = list_of_strings[i]
            # If the current string is shorter than the potential prefix or doesn't start with it, it's not common
            if len(current_string) < prefix_length or current_string[:prefix_length] != potential_prefix:
                is_common_to_all = False
                break
        # If the potential prefix was not common to all strings, the previous prefix was the longest common one
        if not is_common_to_all:
            return reference_string[:prefix_length - 1]
    # If the loop completes, the entire reference string is the longest common prefix
    return reference_string

