            if current_char_index >= current_other_string.len() ||
               current_other_string.chars().nth(current_char_index).unwrap() != character_to_check {
                return reference_string[0..prefix_length].to_string();
            }
        }
        // If the character matched all strings, extend the current prefix length
        prefix_length += 1;
